import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Empty / processing fee
  it.todo("empty item list quote yields premium of 5 G (processing fee only)");

  // Single-item base premiums
  it.todo("quote for a single sword yields 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("quote for a single amulet yields 71 G (60 base + 6 first insurance + 5 fee)");
  it.todo("quote for a single staff yields 93 G (80 base + 8 first insurance + 5 fee)");
  it.todo("quote for a single potion yields 49 G (40 base + 4 first insurance + 5 fee)");

  // Components
  it.todo("quote for a single rune component yields 33 G (25 base + 2.5 first insurance + 5 fee, rounded up)");
  it.todo("quote for 2 runes yields 60 G (50 base + 5 first insurance + 5 fee)");
  it.todo("quote for 3 runes applies block discount: yields 71 G (60 base + 6 first insurance + 5 fee)");
  it.todo("quote for 4 runes yields no block: 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("quote for 3 runes + 3 moonstones yields two blocks: 137 G (120 base + 12 first insurance + 5 fee)");
  it.todo("quote for 2 runes + 1 moonstone yields no block: 88 G (75 base + 7.5 first insurance + 5 fee, rounded up)");

  // Modifiers
  it.todo("cursed sword for newcomer with 0 years yields 165 G (integration example)");
  it.todo("highly enchanted sword (enchantment 5) for newcomer yields 148 G (100 + 30 + 10 + 5 fee)");
  it.todo("long-standing customer (2 years) with plain sword: 20% loyalty discount applied");
  it.todo("follow-up contract (second quote) applies 15% discount on policy base");
  it.todo("cursed sword + plain amulet for newcomer: cursed surcharge applies only to sword");

  // Integration
  it.todo("long-standing customer's second contract with cursed enchanted sword yields 160 G");

  // Rounding in MHPCO favor
  it.todo("premium calculation yielding 197.5 G rounds up to 198 G");

  // Claim - basic
  it.todo("claim for steel sword enchantment 3, damage 500 G: payout 400 G");
  it.todo("claim for rune (no enchantment, no material), damage 200 G: payout 100 G");
  it.todo("claim for high-enchantment sword (enchantment 9), damage 1000 G: payout 400 G");
  it.todo("claim for dragon-material sword (enchantment 5), damage 800 G: payout 700 G");
  it.todo("claim for dragon-material sword with enchantment 9: 50% rule wins, then deductible");
  it.todo("claim with multiple damages applies deductible per damage event");

  // Claim - cap
  it.todo("policy with sword has cap 2000 G; two 1500 G claims: first payout 1400, then 600");
  it.todo("claim payout rounds down (350.5 → 350)");

  // Errors
  it.todo("quote with unknown item type rejects");
  it.todo("claim referencing item not in policy rejects");
  it.todo("claim with negative amount rejects");
  it.todo("claim with more damaged items than insured rejects");
});

