type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;

const itemPremium = (item: Item): number => {
  if (item.type === "sword") return 110; // base 100 + 10 first insurance
  return 0;
};

const quotePremium = (items: Item[]): number => {
  const itemsSum = items.reduce((sum, item) => sum + itemPremium(item), 0);
  return itemsSum + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

