type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
  componentType?: string;
};
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE = 25;
const COMPONENT_BLOCK_BASE = 60;
const BLOCK_SIZE = 3;

const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

// Returns list of base premiums for components, grouping into blocks of 3 alike.
const componentBases = (items: Item[]): number[] => {
  const components = items.filter((i) => i.type === "component");
  const byType: Record<string, number> = {};
  for (const c of components) {
    const key = c.componentType ?? "unknown";
    byType[key] = (byType[key] ?? 0) + 1;
  }
  const bases: number[] = [];
  for (const count of Object.values(byType)) {
    if (count === BLOCK_SIZE) {
      bases.push(COMPONENT_BLOCK_BASE);
    } else {
      for (let i = 0; i < count; i++) bases.push(COMPONENT_BASE);
    }
  }
  return bases;
};

const itemBases = (items: Item[]): number[] => {
  const mainBases = items.filter((i) => i.type !== "component").map(mainItemBase);
  return [...mainBases, ...componentBases(items)];
};

const ceilG = (amount: number): number => {
  // Round up to whole G, with epsilon to avoid float artifacts.
  const EPS = 1e-9;
  return Math.ceil(amount - EPS);
};

const quotePremium = (items: Item[]): number => {
  const bases = itemBases(items);
  // First insurance surcharge applies per item (each base * 1.1)
  const itemsSum = bases.reduce((sum, base) => sum + base * (1 + FIRST_INSURANCE_SURCHARGE), 0);
  return ceilG(itemsSum + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

